# Parameters make functions flexible
def classify_port(port):
    if port < 1024:
        return "Well-known"
    elif port < 49152:
        return "Registered"
    else:
        return "Dynamic"

# Same function, different arguments
print(classify_port(80))     # Well-known
print(classify_port(8080))   # Registered
print(classify_port(55000))  # Dynamic

# Default parameters — sensible forensic defaults
def hash_text(text, algorithm="sha256"):
    import hashlib
    if algorithm == "md5":
        return hashlib.md5(text.encode()).hexdigest()
    elif algorithm == "sha256":
        return hashlib.sha256(text.encode()).hexdigest()
    else:
        return "Unknown algorithm"

# Use default (sha256)
print(hash_text("evidence"))

# Override with md5
print(hash_text("evidence", "md5"))

# Named argument (clearer)
print(hash_text("evidence", algorithm="md5"))

# *args — any number of positional arguments
def scan_files(*filenames):
    print(f"Scanning {len(filenames)} files:")
    for f in filenames:
        print(f"  Processing: {f}")

scan_files("a.jpg", "b.pdf")
scan_files("x.exe", "y.bat", "z.ps1", "w.doc")

# **kwargs — any number of keyword arguments
def generate_report(**options):
    print("Report settings:")
    for key, value in options.items():
        print(f"  {key}: {value}")

generate_report(format="PDF", verbose=True, author="Analyst")

