# Breaking complex tasks into small functions
# Each function does ONE job well

def parse_log_line(line):
    """Parse a single log line into structured data."""
    parts = line.split(" ", 3)
    if len(parts) < 4:
        return None
    return {
        "date": parts[0],
        "time": parts[1],
        "level": parts[2],
        "message": parts[3]
    }

def is_threat(entry):
    """Check if a log entry indicates a threat."""
    if entry is None:
        return False
    threat_words = ["FAILED", "ERROR", "DENIED", "BLOCKED", "ATTACK"]
    return any(word in entry["message"].upper() for word in threat_words)

def get_severity(entry):
    """Determine severity from log level."""
    levels = {"CRITICAL": 4, "ERROR": 3, "WARNING": 2, "INFO": 1, "DEBUG": 0}
    return levels.get(entry["level"], 0)

def analyse_logs(log_lines):
    """Analyse a list of log lines and return a summary."""
    total = 0
    threats = []
    by_level = {}

    for line in log_lines:
        entry = parse_log_line(line)
        if entry is None:
            continue
        total += 1
        by_level[entry["level"]] = by_level.get(entry["level"], 0) + 1
        if is_threat(entry):
            threats.append(entry)

    return {"total": total, "threats": len(threats), "by_level": by_level, "threat_details": threats}

# Sample logs
logs = [
    "2025-02-28 08:00:01 INFO Server started successfully",
    "2025-02-28 08:15:22 WARNING Login FAILED for user admin",
    "2025-02-28 08:15:23 WARNING Login FAILED for user admin",
    "2025-02-28 08:30:00 ERROR Connection DENIED from 10.0.0.99",
    "2025-02-28 09:00:00 INFO Backup completed",
    "2025-02-28 10:00:00 CRITICAL Possible ATTACK detected from 203.0.113.42",
    "2025-02-28 11:00:00 INFO System health check OK",
]

result = analyse_logs(logs)
print(f"Total entries: {result['total']}")
print(f"Threats found: {result['threats']}")
print(f"By level: {result['by_level']}")
print(f"\nThreat details:")
for t in result["threat_details"]:
    print(f"  [{t['level']}] {t['time']} - {t['message']}")

# IP Address Forensic Toolkit
# A collection of related functions

def is_valid_ipv4(ip):
    """Check if a string is a valid IPv4 address."""
    parts = ip.split(".")
    if len(parts) != 4:
        return False
    for part in parts:
        if not part.isdigit():
            return False
        if not (0 <= int(part) <= 255):
            return False
        if len(part) > 1 and part[0] == "0":  # No leading zeros
            return False
    return True

def classify_ip(ip):
    """Classify an IP as private, loopback, or public."""
    if not is_valid_ipv4(ip):  # Reusing our validator!
        return "INVALID"
    first = int(ip.split(".")[0])
    second = int(ip.split(".")[1])
    if ip.startswith("127."):
        return "LOOPBACK"
    elif first == 10:
        return "PRIVATE (Class A)"
    elif first == 172 and 16 <= second <= 31:
        return "PRIVATE (Class B)"
    elif first == 192 and second == 168:
        return "PRIVATE (Class C)"
    else:
        return "PUBLIC"

def ip_to_int(ip):
    """Convert IPv4 to 32-bit integer."""
    parts = [int(p) for p in ip.split(".")]
    return (parts[0] << 24) + (parts[1] << 16) + (parts[2] << 8) + parts[3]

def ip_to_hex(ip):
    """Convert IPv4 to hex representation."""
    return ".".join(f"{int(p):02X}" for p in ip.split("."))

# Test the toolkit
test_ips = [
    "192.168.1.1", "10.0.0.5", "8.8.8.8", "127.0.0.1",
    "172.16.0.1", "256.1.1.1", "not_an_ip"
]

print("IP ADDRESS ANALYSIS")
print("=" * 65)
for ip in test_ips:
    valid = is_valid_ipv4(ip)
    if valid:
        cls = classify_ip(ip)
        hex_ip = ip_to_hex(ip)
        int_ip = ip_to_int(ip)
        print(f"{ip:<18} {cls:<20} Hex: {hex_ip:<15} Int: {int_ip}")
    else:
        print(f"{ip:<18} INVALID")
print("=" * 65)

